# Remove the client socket from inputs and outputs
                            if s in inputs:
                                inputs.remove(s)
                            if s in outputs:
                                outputs.remove(s)
                            # Clean up the message queue
                            del message_queues[s]
                            status_message += f"Connection closed with {s.getpeername()}\n"
                    except Exception as e:
                        # Handle any errors during data reception
                        status_message += f"Error receiving data from {s.getpeername()}: {e}\n"
                        if s in inputs:
                            inputs.remove(s)
                        if s in outputs:
                            outputs.remove(s)
                        del message_queues[s]

            # Handle writable sockets
            for s in writable:
                try:
                    if not message_queues[s].empty():
                        # Send data to the client
                        next_msg = message_queues[s].get_nowait()
                        s.send(next_msg)
                        status_message += f"Sent response to {s.getpeername()}\n"
                    else:
                        # No more data to send, remove from outputs
                        outputs.remove(s)
                except Exception as e:
                    # Handle any errors during data transmission
                    status_message += f"Error sending data to {s.getpeername()}: {e}\n"
                    outputs.remove(s)
                    del message_queues[s]

            # Handle exceptional conditions
            for s in exceptional:
                status_message += f"Exceptional condition on {s.getpeername()}\n"
                if s in inputs:
                    inputs.remove(s)
                if s in outputs:
                    outputs.remove(s)
                del message_queues[s]

    except Exception as e:
        status_message += f"Server error: {e}\n"

    finally:
        # Close all client connections
        for s in inputs:
            if s is not server_socket:
                s.close()
        server_socket.close()

    # Calculate the run duration
    run_duration_actual = (datetime.now() - start_time).total_seconds()
    status_message += f"Echo server stopped. Total run time: {run_duration_actual:.2f} seconds.\n"

    return status_message

